Instant instant_curr = Instant.ofEpochMilli(current_millis);
ZonedDateTime zdt_curr = ZonedDateTime.ofInstant(instant_curr, ZoneId.of('+7'));

// Go to the start of the current month, then subtract one month to get the start of the previous month
ZonedDateTime start_of_current_month = zdt_curr.withDayOfMonth(1);
ZonedDateTime start_of_previous_month = start_of_current_month.minusMonths(1);

// Get the year and month format for the previous month
DateTimeFormatter dtf_prev = DateTimeFormatter.ofPattern("yyyyMM");
