{"id":"transform-pivot-population_enrichment_prev_month-v01","authorization":{"roles":["superuser"]},"version":"10.0.0","create_time":1765959591822,"source":{"index":["transform-pivot-population_enrichment"],"query":{"bool":{"filter":[{"range":{"date":{"gte":"2025-01-01T00:00:00","time_zone":"Asia/Jakarta"}}}]}},"runtime_mappings":{"trx_reliability":{"type":"keyword","script":{"source":"def max_date = 99999;
def timestamp2;

if(doc['trx.last_success.created_at'].size()!=0) {
	long last_transaction=doc['trx.last_success.created_at'].value.toInstant().toEpochMilli();
	max_date = last_transaction;
}

long miliSinceEpoch = doc['@timestamp'].value.toInstant().toEpochMilli();
Instant instant = Instant.ofEpochMilli(miliSinceEpoch);
ZonedDateTime zdt = ZonedDateTime.ofInstant(instant, ZoneId.of('+7'));
DateTimeFormatter dtf = DateTimeFormatter.ofPattern("yyyy-MM-dd'T'00:00:00.000'Z'");
String date = zdt.format(dtf);

String dateString = date;
DateTimeFormatter formatter = DateTimeFormatter.ISO_OFFSET_DATE_TIME;
ZonedDateTime zdt2 = ZonedDateTime.parse(dateString, formatter);
long timestamp = zdt2.toInstant().toEpochMilli();

timestamp2 = timestamp - 25200000;

if (max_date >= timestamp2) {
    emit("active");
}
else if (max_date == 99999) {
	emit("not_active");
}
else {
    emit("not_active");
}"}}}},"dest":{"index":"transform-pivot-population_enrichment_prev_month","pipeline":"shift_date_plus_one_month"},"sync":{"time":{"field":"@timestamp","delay":"60s"}},"pivot":{"group_by":{"poi":{"terms":{"field":"poi"}},"date":{"date_histogram":{"field":"date","calendar_interval":"1M","time_zone":"Asia/Jakarta"}}},"aggregations":{"prev":{"filter":{"bool":{"must":[]}},"aggs":{"logon.count_log":{"sum":{"field":"logon.count_log"}},"logon.count_success":{"sum":{"field":"logon.count_success"}},"logon.count_timeout":{"sum":{"field":"logon.count_timeout"}},"hbp.count_log":{"sum":{"field":"hbp.count_log"}},"hbs.count_log":{"sum":{"field":"hbs.count_log"}},"trx.count_log":{"sum":{"field":"trx.count_log"}},"trx.count_print_log":{"sum":{"field":"trx.count_print_log"}},"trx.sum_q1_amount":{"sum":{"field":"trx.sum_q1_amount"}},"trx.count_timeout":{"sum":{"field":"trx.count_timeout"}},"trx.sum_median_amount":{"sum":{"field":"trx.sum_median_amount"}},"trx.count_unique_tid":{"sum":{"field":"trx.count_unique_tid"}},"trx.count_success":{"sum":{"field":"trx.count_success"}},"trx.count_failed":{"sum":{"field":"trx.count_failed"}}}}}},"description":"[USED:1] Mendapatkan summary trx, logon, hbp, dan hbs dari bulan sebelumnya","settings":{}}

